const body = $json.body || $json;
const now = new Date().toISOString();

const targetName = body.target_name || body.targetName || 'unknown-target';
const threadId = body.thread_id || body.threadId || `thread-${Date.now()}`;
const sourcePlatform = body.source_platform || body.sourcePlatform || 'manual';
const rawText = body.raw_text || body.rawText || '';
const messageId = body.message_id || body.messageId || `msg-${Date.now()}`;

return [
  {
    json: {
      intake_timestamp: now,
      target_name: targetName,
      thread_id: threadId,
      source_platform: sourcePlatform,
      raw_text: rawText,
      message_id: messageId,
      current_stage: 'ENTRY',
      state_version: '1.0'
    }
  }
];

const j = $json;

const amo = {
  message_id: j.message_id,
  timestamp: j.intake_timestamp,
  source_agent: 'signal_hunter',
  target_agent: 'constraint_mapper',
  target_entity: {
    name: j.target_name,
    type: 'C'
  },
  interaction_stage: 'ENTRY',
  state_snapshot: {
    signal_strength: 0.5,
    constraint_detected: '',
    authority_gap: '',
    conversion_readiness: 0.0,
    ownership_signal: false,
    uncertainty_signal: false,
    boundary_exposure: false,
    failure_surface_profile: [],
    pressure_ceiling: 'low'
  },
  action_payload: {
    message_text: '',
    intent: 'probe',
    pressure_type: 'none',
    expected_response: 'clarification'
  },
  classification: {
    confidence: 0.5,
    next_best_action: 'hold',
    response_type: 'none'
  },
  handoff_conditions: {
    if_yes: 'forward_to_constraint_mapper',
    if_no: 'archive_or_wait',
    if_ambiguous: 'manual_review'
  },
  thread_context: {
    thread_id: j.thread_id,
    source_platform: j.source_platform,
    prior_message_ids: []
  }
};

return [{ json: { ...j, amo } }];
